15	  private _mappingsMap?: Dictionary<DMMF.ModelMapping>
16	  private _outputTypeMap?: NamespacedTypeMap<DMMF.OutputType>
17	  private _rootFieldMap?: Dictionary<DMMF.SchemaField>
18	
19	  constructor(public document: DMMF.Document) {}
20	
21	  private get compositeNames(): Set<string> {
22	    return (this._compositeNames ??= new Set(this.datamodel.types.map((t) => t.name)))
23	  }
24	
25	  private get inputTypesByName(): Map<FullyQualifiedName, DMMF.InputType> {
26	    return (this._inputTypesByName ??= this.buildInputTypesMap())
27	  }
28	
29	  get typeAndModelMap(): Dictionary<DMMF.Model> {
30	    return (this._typeAndModelMap ??= this.buildTypeModelMap())
31	  }
32	
33	  get mappingsMap(): Dictionary<DMMF.ModelMapping> {
34	    return (this._mappingsMap ??= this.buildMappingsMap())
35	  }
36	
37	  get outputTypeMap(): NamespacedTypeMap<DMMF.OutputType> {
38	    return (this._outputTypeMap ??= this.buildMergedOutputTypeMap())
39	  }
40	
41	  get rootFieldMap(): Dictionary<DMMF.SchemaField> {
42	    return (this._rootFieldMap ??= this.buildRootFieldMap())
43	  }
44	
45	  get datamodel(): DMMF.Datamodel {
46	    return this.document.datamodel
47	  }
48	
49	  get mappings(): DMMF.Mappings {
50	    return this.document.mappings
51	  }
52	
53	  get schema(): DMMF.Schema {
54	    return this.document.schema
55	  }
56	
57	  get inputObjectTypes(): DMMF.Schema['inputObjectTypes'] {
58	    return this.schema.inputObjectTypes
59	  }
60	
61	  get outputObjectTypes(): DMMF.Schema['outputObjectTypes'] {
62	    return this.schema.outputObjectTypes
63	  }
64	
65	  isComposite(modelOrTypeName: string) {
66	    return this.compositeNames.has(modelOrTypeName)
67	  }
68	
69	  getOtherOperationNames() {
70	    return [
71	      Object.values(this.mappings.otherOperations.write),
72	      Object.values(this.mappings.otherOperations.read),
73	    ].flat()
74	  }
75	
76	  hasEnumInNamespace(enumName: string, namespace: DMMF.FieldNamespace): boolean {
77	    return this.schema.enumTypes[namespace]?.find((schemaEnum) => schemaEnum.name === enumName) !== undefined
78	  }
79	
80	  resolveInputObjectType(ref: DMMF.InputTypeRef): DMMF.InputType | undefined {
81	    return this.inputTypesByName.get(fullyQualifiedName(ref.type, ref.namespace))
82	  }
83	
84	  resolveOutputObjectType(ref: DMMF.OutputTypeRef): DMMF.OutputType | undefined {
85	    if (ref.location !== 'outputObjectTypes') {
86	      return undefined
87	    }
88	    return this.outputObjectTypes[ref.namespace ?? 'prisma'].find((outputObject) => outputObject.name === ref.type)
89	  }
90	
91	  private buildModelMap(): Dictionary<DMMF.Model> {
92	    return keyBy(this.datamodel.models, 'name')
93	  }
94	
95	  private buildTypeMap(): Dictionary<DMMF.Model> {
96	    return keyBy(this.datamodel.types, 'name')
97	  }
98	
99	  private buildTypeModelMap(): Dictionary<DMMF.Model> {
100	    return { ...this.buildTypeMap(), ...this.buildModelMap() }
101	  }
102	
103	  private buildMappingsMap(): Dictionary<DMMF.ModelMapping> {
104	    return keyBy(this.mappings.modelOperations, 'model')
105	  }
106	
107	  private buildMergedOutputTypeMap(): NamespacedTypeMap<DMMF.OutputType> {
108	    if (!this.schema.outputObjectTypes.prisma) {
109	      return {
110	        model: keyBy(this.schema.outputObjectTypes.model, 'name'),
111	        prisma: keyBy([], 'name'),
112	      }
113	    }
114	
115	    return {
116	      model: keyBy(this.schema.outputObjectTypes.model, 'name'),
117	      prisma: keyBy(this.schema.outputObjectTypes.prisma, 'name'),
118	    }
119	  }
120	
121	  private buildRootFieldMap(): Dictionary<DMMF.SchemaField> {
122	    return {
123	      ...keyBy(this.outputTypeMap.prisma.Query.fields, 'name'),
124	      ...keyBy(this.outputTypeMap.prisma.Mutation.fields, 'name'),
125	    }
126	  }
127	
128	  private buildInputTypesMap() {
129	    const result = new Map<FullyQualifiedName, DMMF.InputType>()
130	    for (const type of this.inputObjectTypes.prisma ?? []) {
131	      result.set(fullyQualifiedName(type.name, 'prisma'), type)
132	    }
133	
134	    if (!this.inputObjectTypes.model) {
135	      return result
136	    }
137	
138	    for (const type of this.inputObjectTypes.model) {
139	      result.set(fullyQualifiedName(type.name, 'model'), type)
140	    }
141	    return result
142	  }
143	}
144	
145	function fullyQualifiedName(typeName: string, namespace?: string) {
146	  if (namespace) {
147	    return `${namespace}.${typeName}` as FullyQualifiedName
148	  }
149	  return typeName as FullyQualifiedName
150	}
