### 3.1 `tests/codegen.test.ts`

Unit tests for the code-generation logic. These tests are pure in-memory; no file I/O, no subprocess spawning.

```typescript
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../src/codegen'
import type * as DMMF from '@prisma/dmmf'

function makeDocument(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: { inputObjectTypes: { prisma: [] }, outputObjectTypes: { model: [], prisma: [] }, enumTypes: { prisma: [] }, fieldRefTypes: {} },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  }
}

function makeModel(name: string, fields: Partial<DMMF.Field>[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields: fields.map((f) => ({
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'String',
      ...f,
    })) as DMMF.Field[],
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

describe('generateRestClient', () => {
  test('generates expected files for a simple model', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
        { name: 'email', isRequired: false, type: 'String' },
      ]),
    ])

    const files = generateRestClient(doc)

    expect(files.has('User.ts')).toBe(true)
    expect(files.has('index.ts')).toBe(true)
    expect(files.has('prisma-rest-client.ts')).toBe(true)
    expect(files.has('_utils.ts')).toBe(true)
  })

  test('User.ts contains correct interface', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
        { name: 'email', isRequired: false, type: 'String' },
      ]),
    ])
    const content = generateRestClient(doc).get('User.ts')!

    expect(content).toContain('export interface User {')
    expect(content).toContain('id: number')
    expect(content).toContain('name: string')
    expect(content).toContain('email?: string | null')
  })

  test('CreateInput excludes auto-generated id', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
      ]),
    ])
    const content = generateRestClient(doc).get('User.ts')!

    expect(content).toContain('export interface UserCreateInput {')
    expect(content).not.toMatch(/UserCreateInput \{[^}]*\bid\b/)
    expect(content).toContain('name: string')
  })

  test('CreateInput keeps non-auto id field', () => {
    const doc = makeDocument([
      makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: false, type: 'String' },
        { name: 'title', isRequired: true, type: 'String' },
      ]),
    ])
    const content = generateRestClient(doc).get('Post.ts')!
    expect(content).toMatch(/UserCreateInput|PostCreateInput/)
    expect(content).toContain('id: string')
  })

  test('UpdateInput excludes @updatedAt fields', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
        { name: 'updatedAt', isUpdatedAt: true, type: 'DateTime' },
      ]),
    ])
    const content = generateRestClient(doc).get('User.ts')!
    expect(content).not.toMatch(/UserUpdateInput \{[^}]*updatedAt/)
  })

  test('UpdateInput excludes relation fields', () => {
    const doc = makeDocument([
      makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'author', kind: 'object', type: 'User', isRequired: false },
      ]),
    ])
    const content = generateRestClient(doc).get('Post.ts')!
    expect(content).not.toMatch(/PostUpdateInput \{[^}]*author/)
  })

  test('WhereUniqueInput contains only id and unique fields', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'email', isUnique: true, type: 'String' },
        { name: 'name', isRequired: true, type: 'String' },
      ]),
    ])
    const content = generateRestClient(doc).get('User.ts')!
    expect(content).toContain('export interface UserWhereUniqueInput {')
    expect(content).toContain('id?: number')
    expect(content).toContain('email?: string')
    expect(content).not.toMatch(/WhereUniqueInput \{[^}]*name/)
  })

  test('enum field uses enum name as type', () => {
    const doc = makeDocument(
      [makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'status', kind: 'enum', type: 'PostStatus', isRequired: true },
      ])],
      [{ name: 'PostStatus', values: [{ name: 'DRAFT', dbName: null }, { name: 'PUBLISHED', dbName: null }] }],
    )
    const content = generateRestClient(doc).get('Post.ts')!
    expect(content).toContain('status: PostStatus')
  })

  test('barrel re-exports all models', () => {
    const doc = makeDocument([
      makeModel('User', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
      makeModel('Post', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
    ])
    const barrel = generateRestClient(doc).get('index.ts')!
    expect(barrel).toContain("export * from './User'")
    expect(barrel).toContain("export * from './Post'")
  })

  test('PrismaRestClient contains all model clients as properties', () => {
    const doc = makeDocument([
      makeModel('User', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
      makeModel('Post', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
