        { name: 'intField', type: 'Int', isRequired: true },
        { name: 'floatField', type: 'Float', isRequired: true },
        { name: 'boolField', type: 'Boolean', isRequired: true },
        { name: 'dtField', type: 'DateTime', isRequired: true },
        { name: 'jsonField', type: 'Json', isRequired: true },
        { name: 'bytesField', type: 'Bytes', isRequired: true },
        { name: 'bigIntField', type: 'BigInt', isRequired: true },
        { name: 'decimalField', type: 'Decimal', isRequired: true },
