### 2.5 `src/scalar-map.ts`

This module owns the Prisma scalar → TypeScript type mapping. It is isolated so it can be tested independently.

```typescript
import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'number',
  Boolean: 'boolean',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

export function fieldToTsType(field: DMMF.Field): string {
  if (field.kind === 'unsupported') {
    return 'unknown'
  }

  if (field.kind === 'enum') {
    return field.type
  }

  if (field.kind === 'object') {
    return field.type
  }

  const mapped = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  const base = field.isList ? `${mapped}[]` : mapped

  if (!field.isRequired) {
    return `${base} | null`
  }

  return base
}
```

**Notes:**
- `DateTime` maps to `string` per spec (ISO 8601). The existing `client-generator-js` maps it to `Date | string`; we deliberately simplify to `string` for REST transport.
- `Bytes` maps to `string` (base64) per spec.
- `isList` wraps in array notation before nullability is applied, so a nullable list is `string[] | null` not `(string | null)[]`.

