### 2.6 `src/codegen.ts`

This is the core code-generation module. It takes a `DMMF.Document` and returns a map of relative output paths to file content strings.

**Field filtering rules for input types (key edge cases):**

| Field attribute | CreateInput | UpdateInput |
|---|---|---|
| `isId: true` with `hasDefaultValue: true` | exclude | include (as optional) |
| `isId: true` with `hasDefaultValue: false` | include (required) | include (as optional) |
| `isUpdatedAt: true` | exclude | exclude |
| `kind === 'object'` (relations) | exclude | exclude |
| `isRequired: false` | optional (`?`) | optional (`?`) |
| `isRequired: true` | required | optional (PATCH semantics) |

**`WhereUniqueInput`:** include only fields where `isId: true` or `isUnique: true` and `kind === 'scalar'`.

**URL pluralisation:** Convert model name to lowercase plural using a simple `lowerFirst + 's'` convention (e.g., `User` → `users`, `Post` → `posts`). Note: this avoids adding a `pluralize` dependency. For a more correct implementation, `pluralize` could be added later.

**Sketch of `codegen.ts`:**

```typescript
import type * as DMMF from '@prisma/dmmf'

import { fieldToTsType } from './scalar-map'

export type GeneratedFiles = Map<string, string>

export function generateRestClient(document: DMMF.Document): GeneratedFiles {
  const files: GeneratedFiles = new Map()
  const models = document.datamodel.models
  const enums = document.datamodel.enums

  for (const model of models) {
    files.set(`${model.name}.ts`, generateModelFile(model))
  }

  files.set('index.ts', generateBarrel(models))
  files.set('prisma-rest-client.ts', generateTopLevelClient(models))

  return files
}

function generateModelFile(model: DMMF.Model): string {
  const sections: string[] = []

  sections.push(generateModelInterface(model))
  sections.push(generateCreateInput(model))
  sections.push(generateUpdateInput(model))
  sections.push(generateWhereUniqueInput(model))
  sections.push(generateRestClientClass(model))

  return sections.join('\n\n') + '\n'
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const tsType = fieldToTsType(f)
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isUpdatedAt) return false
      if (f.isId && f.hasDefaultValue) return false
      return true
    })
    .map((f) => {
      const tsType = fieldToTsType(f)
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isUpdatedAt) return false
      if (f.isId) return false
      return true
    })
    .map((f) => {
      const tsType = fieldToTsType(f)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => (f.isId || f.isUnique) && f.kind === 'scalar')
    .map((f) => {
      const tsType = fieldToTsType(f)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

function generateRestClientClass(model: DMMF.Model): string {
  const resourcePath = toResourcePath(model.name)
  const name = model.name

  return `export class ${name}RestClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = params ? toQueryString(params) : ''
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}\${query}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${id}\`)
    if (res.status === 404) return null
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${id}\`, { method: 'DELETE' })
    return res.json() as Promise<${name}>
  }
}`
}

function generateBarrel(models: readonly DMMF.Model[]): string {
  return models.map((m) => `export * from './${m.name}'`).join('\n') + '\n'
}

function generateTopLevelClient(models: readonly DMMF.Model[]): string {
  const imports = models
    .map((m) => `import { ${m.name}RestClient } from './${m.name}'`)
    .join('\n')

  const props = models
    .map((m) => `  readonly ${lowerFirst(m.name)}: ${m.name}RestClient`)
    .join('\n')

  const assignments = models
    .map((m) => `    this.${lowerFirst(m.name)} = new ${m.name}RestClient(baseUrl)`)
    .join('\n')

  return `${imports}

export class PrismaRestClient {
${props}

  constructor(baseUrl: string) {
${assignments}
  }
}
`
}

function toResourcePath(modelName: string): string {
  return lowerFirst(modelName) + 's'
}

function lowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

function toQueryString(params: Record<string, unknown>): string {
  const entries = Object.entries(params).filter(([, v]) => v !== undefined)
  if (entries.length === 0) return ''
  return '?' + entries.map(([k, v]) => `${k}=${encodeURIComponent(String(v))}`).join('&')
}

function extractId(where: Record<string, unknown>): string | number {
  const value = Object.values(where).find((v) => v !== undefined)
  if (value === undefined) {
    throw new Error('WhereUniqueInput must have at least one field set')
  }
  return value as string | number
}
```

**Design notes for `codegen.ts`:**
- `toQueryString` and `extractId` are emitted as helper functions at the top of each generated file (injected once in the barrel or as a shared `prisma-rest-client-utils.ts`). See the barrel and top-level client section below.
- The `fetch` calls use the global `fetch` API (available in Node 18+ and all modern runtimes). No import is needed.
- Private fields use `#baseUrl` per the native JS private fields convention.
- The `generateRestClientClass` embeds the helper functions inline in each model file. An alternative is to put `toQueryString` and `extractId` in a shared `_utils.ts` file imported by each model file. Given the simplicity, the inline approach is cleaner unless you expect users to also use the model files standalone. The plan below puts them in a shared file to avoid duplication.

**Revised structure for helper functions:**

Add a `generated/_utils.ts` file (or embed helpers in `prisma-rest-client.ts`). The cleaner approach: emit a `_utils.ts` alongside the model files in the output directory. The barrel does not re-export it. Model files import from `./_utils`.

Generated output structure (inside `outputDir`):
```
User.ts           ← model interface + rest client class
Post.ts
index.ts          ← barrel
prisma-rest-client.ts  ← top-level PrismaRestClient class
_utils.ts         ← shared toQueryString + extractId helpers
```

`_utils.ts` content (generated once):
