    const content = generateRestClient(doc).get('Post.ts')!
    expect(content).toContain('status: PostStatus')
  })

  test('barrel re-exports all models', () => {
    const doc = makeDocument([
      makeModel('User', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
      makeModel('Post', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
    ])
    const barrel = generateRestClient(doc).get('index.ts')!
    expect(barrel).toContain("export * from './User'")
    expect(barrel).toContain("export * from './Post'")
  })

  test('PrismaRestClient contains all model clients as properties', () => {
    const doc = makeDocument([
      makeModel('User', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
      makeModel('Post', [{ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }]),
