    const topClient = generateRestClient(doc).get('prisma-rest-client.ts')!
    expect(topClient).toContain('readonly user: UserRestClient')
    expect(topClient).toContain('readonly post: PostRestClient')
    expect(topClient).toContain('class PrismaRestClient')
  })

  test('scalar type mapping is correct', () => {
    const doc = makeDocument([
      makeModel('AllTypes', [
        { name: 'strField', type: 'String', isRequired: true },
        { name: 'intField', type: 'Int', isRequired: true },
        { name: 'floatField', type: 'Float', isRequired: true },
        { name: 'boolField', type: 'Boolean', isRequired: true },
        { name: 'dtField', type: 'DateTime', isRequired: true },
        { name: 'jsonField', type: 'Json', isRequired: true },
        { name: 'bytesField', type: 'Bytes', isRequired: true },
        { name: 'bigIntField', type: 'BigInt', isRequired: true },
        { name: 'decimalField', type: 'Decimal', isRequired: true },
      ]),
    ])
    const content = generateRestClient(doc).get('AllTypes.ts')!
    expect(content).toContain('strField: string')
    expect(content).toContain('intField: number')
    expect(content).toContain('floatField: number')
    expect(content).toContain('boolField: boolean')
    expect(content).toContain('dtField: string')
    expect(content).toContain('jsonField: unknown')
    expect(content).toContain('bytesField: string')
    expect(content).toContain('bigIntField: number')
    expect(content).toContain('decimalField: number')
