import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'number',
  Boolean: 'boolean',
  /** ISO 8601 string over REST transport */
  DateTime: 'string',
  Json: 'unknown',
  /** base64-encoded string over REST transport */
  Bytes: 'string',
}

/**
 * Returns the base TypeScript type for a DMMF field, without nullability modifiers.
 * List fields are wrapped in `T[]`. Nullability (`| null`) is left to the caller.
 */
export function fieldToBaseType(field: Field): string {
  let base: string

  if (field.kind === 'unsupported') {
    base = 'unknown'
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  return field.isList ? `${base}[]` : base
}

