import { describe, expect, test } from 'vitest'

import type { DatamodelEnum, Document, Field, Model } from '@prisma/dmmf'

import { generateRestClient } from '../src/codegen'

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: 'String',
    ...overrides,
  } as Field
}

function makeModel(name: string, fields: Partial<Field>[]): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields: fields.map(makeField),
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as Model
}

function makeDocument(models: Model[], enums: DatamodelEnum[] = []): Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  } as unknown as Document
}

describe('generateRestClient', () => {
  test('generates the expected set of output files for a simple model', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
      ]),
    ])

    const files = generateRestClient(doc)

    expect(files.has('User.ts')).toBe(true)
    expect(files.has('index.ts')).toBe(true)
    expect(files.has('prisma-rest-client.ts')).toBe(true)
    expect(files.has('_utils.ts')).toBe(true)
  })

  test('model interface contains correct field types and optionality', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
        { name: 'email', isRequired: false, type: 'String' },
      ]),
    ])

    const content = generateRestClient(doc).get('User.ts')!

    expect(content).toContain('export interface User {')
    expect(content).toContain('  id: number')
    expect(content).toContain('  name: string')
    expect(content).toContain('  email?: string | null')
  })

  test('CreateInput excludes auto-generated ID fields', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
      ]),
    ])

    const content = generateRestClient(doc).get('User.ts')!

    expect(content).toContain('export interface UserCreateInput {')
    // id must not appear inside UserCreateInput (it's auto-generated)
    const createInputBlock = content.slice(
      content.indexOf('export interface UserCreateInput {'),
      content.indexOf('}', content.indexOf('export interface UserCreateInput {')),
    )
    expect(createInputBlock).not.toContain('id')
    expect(content).toContain('  name: string')
  })

  test('CreateInput keeps non-auto ID fields as required', () => {
    const doc = makeDocument([
      makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: false, type: 'String' },
        { name: 'title', isRequired: true, type: 'String' },
      ]),
    ])

    const content = generateRestClient(doc).get('Post.ts')!

    expect(content).toContain('export interface PostCreateInput {')
    expect(content).toContain('  id: string')
    expect(content).toContain('  title: string')
  })

  test('UpdateInput excludes @updatedAt fields', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'name', isRequired: true, type: 'String' },
        { name: 'updatedAt', isUpdatedAt: true, type: 'DateTime' },
      ]),
    ])

    const content = generateRestClient(doc).get('User.ts')!
    const updateInputBlock = content.slice(
      content.indexOf('export interface UserUpdateInput {'),
      content.indexOf('}', content.indexOf('export interface UserUpdateInput {')),
    )

    expect(content).toContain('export interface UserUpdateInput {')
    expect(updateInputBlock).not.toContain('updatedAt')
  })

  test('UpdateInput excludes relation fields', () => {
    const doc = makeDocument([
      makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'author', kind: 'object', type: 'User', isRequired: false },
      ]),
    ])

    const content = generateRestClient(doc).get('Post.ts')!
    const updateInputBlock = content.slice(
      content.indexOf('export interface PostUpdateInput {'),
      content.indexOf('}', content.indexOf('export interface PostUpdateInput {')),
    )

    expect(updateInputBlock).not.toContain('author')
  })

  test('WhereUniqueInput contains only ID and unique scalar fields, all optional', () => {
    const doc = makeDocument([
      makeModel('User', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'email', isUnique: true, type: 'String' },
        { name: 'name', isRequired: true, type: 'String' },
      ]),
    ])

    const content = generateRestClient(doc).get('User.ts')!
    const whereBlock = content.slice(
      content.indexOf('export interface UserWhereUniqueInput {'),
      content.indexOf('}', content.indexOf('export interface UserWhereUniqueInput {')),
    )

    expect(content).toContain('export interface UserWhereUniqueInput {')
    expect(whereBlock).toContain('id?: number')
    expect(whereBlock).toContain('email?: string')
    expect(whereBlock).not.toContain('name')
  })

  test('enum fields use the enum name as their TypeScript type', () => {
    const doc = makeDocument(
      [
        makeModel('Post', [
          { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
          { name: 'status', kind: 'enum', type: 'PostStatus', isRequired: true },
        ]),
      ],
      [{ name: 'PostStatus', values: [{ name: 'DRAFT', dbName: null }, { name: 'PUBLISHED', dbName: null }] }],
    )

