import { describe, expect, test } from 'vitest'

import type { DatamodelEnum, Document, Field, Model } from '@prisma/dmmf'

import { generateRestClient } from '../src/codegen'

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: 'String',
    ...overrides,
  } as Field
}

function makeModel(name: string, fields: Partial<Field>[]): Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields: fields.map(makeField),
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as Model
}

function makeDocument(models: Model[], enums: DatamodelEnum[] = []): Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  } as unknown as Document
}

