    const files = generateRestClient(doc)

    expect(files.has('User.ts')).toBe(true)
    expect(files.has('index.ts')).toBe(true)
    expect(files.has('prisma-rest-client.ts')).toBe(true)
    expect(files.has('_utils.ts')).toBe(true)
  })

