    )

    expect(content).toContain('export interface UserUpdateInput {')
    expect(updateInputBlock).not.toContain('updatedAt')
  })

  test('UpdateInput excludes relation fields', () => {
    const doc = makeDocument([
      makeModel('Post', [
        { name: 'id', isId: true, hasDefaultValue: true, type: 'Int' },
        { name: 'author', kind: 'object', type: 'User', isRequired: false },
      ]),
    ])

    const content = generateRestClient(doc).get('Post.ts')!
    const updateInputBlock = content.slice(
      content.indexOf('export interface PostUpdateInput {'),
      content.indexOf('}', content.indexOf('export interface PostUpdateInput {')),
