import type { DatamodelEnum, Document, Model } from '@prisma/dmmf'

import { fieldToBaseType } from './scalar-map'

export type GeneratedFiles = Map<string, string>

/**
 * Generates all REST client TypeScript source files from a DMMF document.
 * Returns a map of relative filenames to file content strings — no I/O is performed here.
 */
export function generateRestClient(document: Document): GeneratedFiles {
  const files: GeneratedFiles = new Map()
  const { models, enums } = document.datamodel

  for (const model of models) {
    files.set(`${model.name}.ts`, generateModelFile(model, enums))
  }

  files.set('index.ts', generateBarrel(models))
  files.set('prisma-rest-client.ts', generateTopLevelClient(models))
  files.set('_utils.ts', generateUtils())

  return files
}

function generateModelFile(model: Model, enums: readonly DatamodelEnum[]): string {
  const enumNames = new Set(enums.map((e) => e.name))
  const referencedEnums = model.fields
    .filter((f) => f.kind === 'enum' && enumNames.has(f.type))
    .map((f) => f.type)

  const uniqueEnumNames = [...new Set(referencedEnums)]

  const parts: string[] = []

  parts.push("import { extractId, toQueryString } from './_utils'")

  if (uniqueEnumNames.length > 0) {
    parts.push(
      uniqueEnumNames.map((name) => `import type { ${name} } from './index'`).join('\n'),
    )
  }

  parts.push(generateModelInterface(model))
  parts.push(generateCreateInput(model))
  parts.push(generateUpdateInput(model))
  parts.push(generateWhereUniqueInput(model))
  parts.push(generateRestClientClass(model))

  return parts.join('\n\n') + '\n'
}

function generateModelInterface(model: Model): string {
  const lines = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const base = fieldToBaseType(f)
      if (!f.isRequired) {
        return `  ${f.name}?: ${base} | null`
      }
      return `  ${f.name}: ${base}`
    })

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

function generateCreateInput(model: Model): string {
  const lines = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isUpdatedAt) return false
      // Auto-generated IDs are assigned by the server
      if (f.isId && f.hasDefaultValue) return false
      return true
    })
    .map((f) => {
      const base = fieldToBaseType(f)
      const nullable = !f.isRequired ? ' | null' : ''
      // Optional if the field is nullable or has a server-side default
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${base}${nullable}`
    })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

function generateUpdateInput(model: Model): string {
  const lines = model.fields
    .filter((f) => {
      if (f.kind === 'object') return false
      if (f.isUpdatedAt) return false
      // IDs identify the record and are not updatable
      if (f.isId) return false
      return true
    })
    .map((f) => {
      const base = fieldToBaseType(f)
      const nullable = !f.isRequired ? ' | null' : ''
      // All update fields are optional (PATCH semantics)
      return `  ${f.name}?: ${base}${nullable}`
    })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

function generateWhereUniqueInput(model: Model): string {
  const lines = model.fields
    .filter((f) => (f.isId || f.isUnique) && f.kind === 'scalar')
    .map((f) => {
      const base = fieldToBaseType(f)
      const nullable = !f.isRequired ? ' | null' : ''
      return `  ${f.name}?: ${base}${nullable}`
    })

  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

function generateRestClientClass(model: Model): string {
  const name = model.name
  // Simple pluralisation: append 's'. Known limitation for irregular plurals.
  const resource = lowerFirst(name) + 's'

  return `export class ${name}RestClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = params ? toQueryString(params) : ''
    const res = await fetch(\`\${this.#baseUrl}/${resource}\${query}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resource}/\${id}\`)
    if (res.status === 404) return null
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resource}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const id = extractId(where)
    const res = await fetch(\`\${this.#baseUrl}/${resource}/\${id}\`, { method: 'DELETE' })
    return res.json() as Promise<${name}>
  }
}`
}

function generateBarrel(models: readonly Model[]): string {
  return models.map((m) => `export * from './${m.name}'`).join('\n') + '\n'
}

function generateTopLevelClient(models: readonly Model[]): string {
  if (models.length === 0) {
    return 'export class PrismaRestClient {\n  constructor(_baseUrl: string) {}\n}\n'
  }

  const imports = models
    .map((m) => `import { ${m.name}RestClient } from './${m.name}'`)
    .join('\n')

  const props = models
    .map((m) => `  readonly ${lowerFirst(m.name)}: ${m.name}RestClient`)
    .join('\n')

  const assignments = models
    .map((m) => `    this.${lowerFirst(m.name)} = new ${m.name}RestClient(baseUrl)`)
    .join('\n')

  return `${imports}

export class PrismaRestClient {
${props}

  constructor(baseUrl: string) {
${assignments}
  }
}
`
}

function generateUtils(): string {
  return `export function toQueryString(params: Record<string, unknown>): string {
  const entries = Object.entries(params).filter(([, v]) => v !== undefined)
  if (entries.length === 0) return ''
  return '?' + entries.map(([k, v]) => \`\${k}=\${encodeURIComponent(String(v))}\`).join('&')
}

export function extractId(where: Record<string, unknown>): string | number {
  const value = Object.values(where).find((v) => v !== undefined)
  if (value === undefined) {
    throw new Error('WhereUniqueInput must have at least one field set')
  }
  return value as string | number
}
`
}

function lowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

